<?php
namespace App\Http\Controllers\Api;
use App\Domain\Payouts\Actions\CreatePayout;use App\Domain\Payouts\Actions\CreatePayoutBatch;use App\Domain\Payouts\Actions\ProcessPayout;use App\Enums\PayoutType;use App\Http\Controllers\Controller;use App\Models\Payout;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;use Illuminate\Validation\Rule;
class PayoutController extends Controller{public function index():JsonResponse{return response()->json(Payout::query()->latest()->paginate());}public function show(Payout $payout):JsonResponse{return response()->json($payout->load('events'));}public function store(Request $request,CreatePayout $action):JsonResponse{$d=$request->validate(['idempotency_key'=>['required','string','max:120'],'type'=>['required',Rule::enum(PayoutType::class)],'member_id'=>['nullable','ulid'],'currency'=>['sometimes','string','size:3'],'amount_minor'=>['required','integer','min:1'],'beneficiary_name'=>['required','string','max:160'],'bank_code'=>['nullable','string','max:20'],'account_number'=>['nullable','string','between:6,30'],'scheduled_for'=>['nullable','date'],'recurrence_rule'=>['nullable','string','max:255'],'metadata'=>['nullable','array']]);return response()->json($action->execute($d),201);}public function bulk(Request $request,CreatePayoutBatch $action):JsonResponse{$d=$request->validate(['name'=>['required','string','max:160'],'idempotency_key'=>['required','string','max:100'],'items'=>['required','array','min:1','max:1000'],'items.*.type'=>['required',Rule::enum(PayoutType::class)],'items.*.member_id'=>['nullable','ulid'],'items.*.currency'=>['sometimes','string','size:3'],'items.*.amount_minor'=>['required','integer','min:1'],'items.*.beneficiary_name'=>['required','string','max:160'],'items.*.bank_code'=>['nullable','string','max:20'],'items.*.account_number'=>['nullable','string','between:6,30'],'items.*.scheduled_for'=>['nullable','date'],'items.*.metadata'=>['nullable','array']]);return response()->json($action->execute($d),201);}public function approve(Payout $payout,ProcessPayout $action):JsonResponse{return response()->json($action->approve($payout));}public function release(Request $request,Payout $payout,ProcessPayout $action):JsonResponse{$d=$request->validate(['provider'=>['required','string','max:80']]);return response()->json($action->release($payout,$d['provider']));}public function event(Request $request,Payout $payout,ProcessPayout $action):JsonResponse{$d=$request->validate(['provider_event_id'=>['required','string','max:160'],'event_type'=>['required','in:paid,failed,reversed,processing'],'provider_reference'=>['nullable','string','max:160'],'failure_reason'=>['nullable','string','max:1000'],'payload'=>['nullable','array']]);return response()->json($action->providerEvent($payout,$d));}}
